@@ -7442,6 +7442,24 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     }
   }

+  // Check for select instructions with loop-invariant conditions, as they may
+  // be costed differently by the VPlan-based and legacy cost models.
+  ScalarEvolution &SE = *CostCtx.CM.PSE.getSE();
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      if (auto *SI = dyn_cast<SelectInst>(&I)) {
+        // Check if the select condition is loop-invariant
+        const SCEV *CondSCEV = SE.getSCEV(SI->getCondition());
+        if (SE.isLoopInvariant(CondSCEV, TheLoop)) {
+          // This select has a loop-invariant condition and may be costed
+          // differently by the two cost models. Return true to indicate
+          // possible simplifications.
+          return true;
+        }
+      }
+    }
+  }
+
